import{_ as t,o as r,c as a,a2 as i}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Chapter 2: First LLM Call","description":"Connect your Rust CLI to the Anthropic API and send your first message to Claude.","frontmatter":{"title":"Chapter 2: First LLM Call","description":"Connect your Rust CLI to the Anthropic API and send your first message to Claude."},"headers":[],"relativePath":"learn/project/02-first-llm-call/index.md","filePath":"learn/project/02-first-llm-call/index.md"}'),l={name:"learn/project/02-first-llm-call/index.md"};function s(n,e,o,c,h,p){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="first-llm-call" tabindex="-1">First LLM Call <a class="header-anchor" href="#first-llm-call" aria-label="Permalink to &quot;First LLM Call&quot;">​</a></h1><p>This chapter bridges the gap between a local CLI application and a networked AI-powered tool. You will learn how HTTP APIs work at the protocol level, then use the reqwest crate to make real requests to the Anthropic Messages API. Every response comes back as JSON, so you will also learn how serde deserializes structured data into strongly-typed Rust structs.</p><p>Beyond the mechanics of a single request-response cycle, this chapter covers the practical concerns that every production API integration must handle: managing API keys securely through environment variables, dealing with rate limits and transient errors through retry logic, and understanding the message format that Claude expects. You will also get your first taste of async Rust, which is essential for non-blocking I/O in a responsive CLI.</p><p>By the end of this chapter your REPL from Chapter 1 will be able to send a user prompt to Claude and print the response. This is the moment the project stops being a toy and starts becoming an agent.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand the Anthropic Messages API request and response format</li><li>Make HTTP POST requests from Rust using reqwest with proper headers and authentication</li><li>Deserialize JSON responses into typed Rust structs with serde</li><li>Handle API errors, rate limits, and transient failures gracefully</li><li>Manage secrets with environment variables instead of hardcoding them</li><li>Write basic async Rust code with tokio to perform non-blocking network I/O</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/02-first-llm-call/01-understanding-llm-apis.html">Understanding LLM APIs</a></li><li><a href="/project/02-first-llm-call/02-anthropic-api-overview.html">Anthropic API Overview</a></li><li><a href="/project/02-first-llm-call/03-api-keys-and-config.html">API Keys and Config</a></li><li><a href="/project/02-first-llm-call/04-http-in-rust-with-reqwest.html">HTTP in Rust with Reqwest</a></li><li><a href="/project/02-first-llm-call/05-making-your-first-request.html">Making Your First Request</a></li><li><a href="/project/02-first-llm-call/06-parsing-json-with-serde.html">Parsing JSON with Serde</a></li><li><a href="/project/02-first-llm-call/07-message-format-deep-dive.html">Message Format Deep Dive</a></li><li><a href="/project/02-first-llm-call/08-system-prompts.html">System Prompts</a></li><li><a href="/project/02-first-llm-call/09-handling-api-errors.html">Handling API Errors</a></li><li><a href="/project/02-first-llm-call/10-rate-limiting-and-retries.html">Rate Limiting and Retries</a></li><li><a href="/project/02-first-llm-call/11-environment-variables.html">Environment Variables</a></li><li><a href="/project/02-first-llm-call/12-async-rust-basics.html">Async Rust Basics</a></li><li><a href="/project/02-first-llm-call/13-streaming-intro.html">Streaming Intro</a></li><li><a href="/project/02-first-llm-call/14-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 1 completed (working Rust environment, basic Rust syntax)</li><li>An Anthropic API key (free tier is sufficient for all exercises)</li><li>Basic understanding of HTTP request/response cycles</li></ul>',10)])])}const u=t(l,[["render",s]]);export{d as __pageData,u as default};
